const D2R = Math.PI / 180;
const R2D = 180 / Math.PI;

function pmod(x, y) {
  let r = x % y;
  if (r < 0) r += y;
  return r;
}

function horner(x, ...c) {
  let i = c.length - 1;
  let y = c[i];
  while (i > 0) { i--; y = y * x + c[i]; }
  return y;
}

function J2000Century(jd) {
  return (jd - 2451545.0) / 36525;
}

// --- Julian Day from calendar date ---
function jdFromDate(year, month, day, hour, minute, second, utcOffsetHours) {
  const decimalHour = hour + minute / 60 + second / 3600 - utcOffsetHours;
  const dayFrac = day + decimalHour / 24;
  let y = year, m = month;
  if (m <= 2) { y -= 1; m += 12; }
  const a = Math.floor(y / 100);
  const b = 2 - a + Math.floor(a / 4);
  const jd = Math.floor(365.25 * (y + 4716)) + Math.floor(30.6001 * (m + 1)) + dayFrac + b - 1524.5;
  return jd;
}

// --- VSOP87D series evaluation ---
function evalSeries(series, tau) {
  let sum = 0;
  for (const power of Object.keys(series)) {
    const terms = series[power];
    let s = 0;
    for (let i = 0; i < terms.length; i++) {
      const A = terms[i][0], B = terms[i][1], C = terms[i][2];
      s += A * Math.cos(B + C * tau);
    }
    sum += s * Math.pow(tau, Number(power));
  }
  return sum;
}

function vsopPosition(planetData, jd) {
  const tau = (jd - 2451545.0) / 365250; // millennia from J2000
  const lon = pmod(evalSeries(planetData.L, tau), 2 * Math.PI);
  const lat = evalSeries(planetData.B, tau);
  const range = evalSeries(planetData.R, tau);
  return { lon, lat, range };
}

function toXYZ(p) {
  const cl = Math.cos(p.lat);
  return [
    p.range * cl * Math.cos(p.lon),
    p.range * cl * Math.sin(p.lon),
    p.range * Math.sin(p.lat)
  ];
}

function geocentricLon(planetKey, jd) {
  const earthPos = vsopPosition(VSOP_DATA.earth, jd);
  const planetPos = vsopPosition(VSOP_DATA[planetKey], jd);
  const [xe, ye] = toXYZ(earthPos);
  const [xp, yp] = toXYZ(planetPos);
  const x = xp - xe, y = yp - ye;
  return pmod(Math.atan2(y, x) * R2D, 360);
}

// Sun: geocentric = Earth heliocentric longitude + 180 (VSOP87D convention)
function sunLongitude(jd) {
  const earthPos = vsopPosition(VSOP_DATA.earth, jd);
  return pmod((earthPos.lon * R2D) + 180, 360);
}

