function nakshatraOf(siderealLon) {
  const span = 360 / 27; // 13°20'
  const idx = Math.floor(siderealLon / span);
  const posInNakshatra = siderealLon - idx * span;
  const pada = Math.floor(posInNakshatra / (span / 4)) + 1;
  return { name: NAKSHATRAS[idx], lord: NAKSHATRA_LORDS[idx], pada };
}

const SIGNS = ['Овен','Телец','Близнецы','Рак','Лев','Дева','Весы','Скорпион','Стрелец','Козерог','Водолей','Рыбы'];
const SIGN_LORDS = ['Мангал','Шукра','Буддха','Чандра','Сурья','Буддха','Шукра','Мангал','Гуру','Шани','Шани','Гуру'];

function signOf(siderealLon) {
  const idx = Math.floor(siderealLon / 30);
  return { name: SIGNS[idx], index: idx, lord: SIGN_LORDS[idx], degInSign: siderealLon % 30 };
}

// --- Main chart calculation ---
function calculateChart(params) {
  const { year, month, day, hour, minute, second, utcOffset, lat, lon, ayanamshaType } = params;
  const jd = jdFromDate(year, month, day, hour, minute, second, utcOffset);

  const ayanamsha = ayanamshaType === 'raman' ? ramanAyanamsha(jd) : lahiriAyanamsha(jd);

  const tropicalPositions = {
    Солнце: sunLongitude(jd),
    Луна: moonLongitude(jd),
    Меркурий: geocentricLon('mercury', jd),
    Венера: geocentricLon('venus', jd),
    Марс: geocentricLon('mars', jd),
    Юпитер: geocentricLon('jupiter', jd),
    Сатурн: geocentricLon('saturn', jd),
  };
  const rahuTropical = rahuLongitude(jd);
  const ketuTropical = pmod(rahuTropical + 180, 360);
  tropicalPositions['Раху'] = rahuTropical;
  tropicalPositions['Кету'] = ketuTropical;

  const ascTropical = ascendantTropical(jd, lat, lon);

  const planets = {};
  for (const [name, tropLon] of Object.entries(tropicalPositions)) {
    const sidLon = pmod(tropLon - ayanamsha, 360);
    const sign = signOf(sidLon);
    const nak = nakshatraOf(sidLon);
    planets[name] = { siderealLon: sidLon, sign, nakshatra: nak };
  }

  const ascSidereal = pmod(ascTropical - ayanamsha, 360);
  const ascSign = signOf(ascSidereal);
  const ascNak = nakshatraOf(ascSidereal);

  // Whole Sign houses: house N = sign at (ascendant sign index + N - 1) mod 12
  const houses = [];
  for (let h = 1; h <= 12; h++) {
    const signIdx = (ascSign.index + h - 1) % 12;
    houses.push({ house: h, sign: SIGNS[signIdx], signIndex: signIdx });
  }

  // Assign planets to houses (Whole Sign: house = planet's sign relative to ascendant sign)
  for (const [name, p] of Object.entries(planets)) {
    let houseNum = (p.sign.index - ascSign.index + 12) % 12 + 1;
    p.house = houseNum;
  }

  return {
    jd,
    ayanamsha,
    ascendant: { siderealLon: ascSidereal, sign: ascSign, nakshatra: ascNak },
    planets,
    houses,
  };
}

if (typeof window !== 'undefined') {
  window.JyotishEngine = {
    calculateChart, jdFromDate, lahiriAyanamsha, ramanAyanamsha,
    sunLongitude, moonLongitude,
  };
}
if (typeof module !== 'undefined') {
  module.exports = {
    calculateChart, jdFromDate, lahiriAyanamsha, ramanAyanamsha,
    sunLongitude, moonLongitude,
  };
}
